def min_subarray_to_make_sum_divisible(nums, p):
    total = sum(nums)
    target = total % p
    if target == 0:
        return 0
    seen = {0: -1}
    cur = 0
    ans = len(nums)
    for i, x in enumerate(nums):
        cur = (cur + x) % p
        need = (cur - target) % p
        if need in seen:
            ans = min(ans, i - seen[need])
        seen[cur] = i
    return -1 if ans == len(nums) else ans

